{
  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement per-API-key rate limiting middleware. The feature enforces a 100-request-per-60-second rolling window on all authenticated API routes. Four agents have contributed domain rules, architecture, operational requirements, and a code review that corrected the initial architecture.",
    "domain_rules": [
      {
        "rule": "Each API key is allowed 100 requests per 60-second rolling window",
        "testable_assertion": "Given an API key that has made 100 requests within the last 60 seconds, the next request returns HTTP 429"
      },
      {
        "rule": "HTTP 429 responses must include a Retry-After header with the number of seconds until the client can retry",
        "testable_assertion": "The Retry-After value reflects the actual time until enough of the window has expired to allow a new request, not a fixed/hardcoded value"
      },
      {
        "rule": "The rate limit window is a true rolling/sliding window, not a fixed window",
        "testable_assertion": "A client that sends 100 requests at second 59 cannot send another 100 at second 61 — the window slides per-request, not per-bucket"
      },
      {
        "rule": "Rate limiter must fail open when Redis is unavailable",
        "testable_assertion": "If Redis is down, requests are allowed through and a redis_unavailable_total metric is incremented"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Use Redis sorted sets for a true sliding window (NOT fixed window counters)",
        "implementation_note": "MJ originally proposed a sliding window counter with key pattern rate_limit:{api_key}:{window_start_unix} and 60s TTL. Kobe's review identified this as a fixed window vulnerable to boundary bursts (up to 200 requests in a 1-second span at the boundary). Use a sorted set per API key instead: ZADD rate_limit:{api_key} with timestamp scores, ZREMRANGEBYSCORE to prune entries older than 60s, ZCARD to count. Set a 60s TTL on the key as a safety net."
      },
      {
        "decision": "Middleware placement: before all authenticated routes",
        "implementation_note": "The rate limit check runs after authentication (so the API key is known) but before any route handler logic."
      },
      {
        "decision": "Retry-After computation: derive from actual window state",
        "implementation_note": "Compute Retry-After as the time until the oldest request in the sorted set expires from the 60-second window. Example: if the oldest of the 100 entries has timestamp T, then Retry-After = 60 - (now - T), rounded up to the nearest second."
      },
      {
        "decision": "Fail-open on Redis unavailability",
        "implementation_note": "Wrap all Redis calls in try/catch. On any Redis error, allow the request through, increment redis_unavailable_total metric, and log a warning. This must be explicitly tested — do not rely on implicit error handling."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "101st request in a 60-second window is rejected",
        "given": "An API key has made 100 requests in the last 60 seconds",
        "when": "A 101st request arrives",
        "then": "HTTP 429 is returned with a Retry-After header showing seconds until the window allows a new request"
      },
      {
        "criterion": "Window resets correctly over time",
        "given": "An API key made its first request 61 seconds ago and has not exceeded the limit in the current sliding window",
        "when": "A new request arrives",
        "then": "The request succeeds with HTTP 2xx"
      },
      {
        "criterion": "No boundary burst vulnerability",
        "given": "An API key sends 99 requests at T=59s and 1 request at T=60s",
        "when": "Another request arrives at T=60.5s",
        "then": "The request is rejected because 100 requests exist within the trailing 60-second window"
      },
      {
        "criterion": "Fail-open when Redis is down",
        "given": "Redis is unavailable",
        "when": "Any authenticated request arrives",
        "then": "The request is allowed through, redis_unavailable_total is incremented, and a warning is logged"
      },
      {
        "criterion": "Observability metrics are emitted",
        "given": "Rate limiting is active",
        "when": "A request is rate-limited OR Redis is unavailable",
        "then": "rate_limit_exceeded_total or redis_unavailable_total counters are incremented respectively"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "rolling window",
        "technical_term": "sliding window via Redis sorted set",
        "definition": "A 60-second window that slides continuously with real time. Every request is evaluated against the count of requests in the preceding 60 seconds from the current moment — not aligned to fixed bucket boundaries."
      },
      {
        "domain_term": "Retry-After",
        "technical_term": "TTL of oldest entry in sorted set",
        "definition": "The number of whole seconds until the oldest request in the current 100-request set ages out of the 60-second window, making room for a new request."
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "MJ proposed a 'sliding window counter' using fixed window keys (rate_limit:{api_key}:{window_start_unix}), but Bird's domain rule specifies a 'rolling window'. Kobe's review confirmed MJ's design is actually a fixed window, vulnerable to 2x burst at bucket boundaries.",
        "resolution": "Adopted Kobe's recommendation: use Redis sorted sets (ZADD/ZREMRANGEBYSCORE/ZCARD) for a true sliding window. This satisfies Bird's rolling window requirement and eliminates the boundary burst vulnerability."
      }
    ],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain rules are clear and unambiguous — 100 req / 60s rolling window, 429 + Retry-After",
      "Architecture corrected by Kobe review — sorted set approach is well-understood and standard",
      "Operational requirements (fail-open, metrics) are concrete and testable"
    ],
    "low_confidence_areas": [
      "Redis sorted set memory overhead at high API key cardinality — not analyzed by any agent, but unlikely to be an issue at typical scale"
    ],
    "assumptions": [
      "API key is available in the request context after authentication middleware — no agent specified the extraction mechanism",
      "A single Redis instance (or cluster) is already available in the infrastructure — Pippen's fail-open concern implies Redis exists but may have availability gaps"
    ]
  }
}

